/**
 * MedicationCard Component
 * Displays a single medication with progress bar and actions
 */

import React, { useState } from "react";

function MedicationCard({ medication, onDelete, onRefill }) {
  // State for showing refill modal
  const [showRefillModal, setShowRefillModal] = useState(false);
  const [refillQuantity, setRefillQuantity] = useState(
    medication.totalQuantity,
  );

  // Calculate percentage of pills remaining
  const percentRemaining = Math.round(
    (medication.remainingStock / medication.totalQuantity) * 100,
  );

  // Determine progress bar color based on percentage
  const getProgressColor = () => {
    if (percentRemaining <= 15) return "bg-red-500"; // Critical - Red
    if (percentRemaining <= 30) return "bg-orange-500"; // Warning - Orange
    if (percentRemaining <= 50) return "bg-yellow-500"; // Caution - Yellow
    return "bg-green-500"; // Good - Green
  };

  // Format the start date for display
  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString("en-US", {
      year: "numeric",
      month: "short",
      day: "numeric",
    });
  };

  // Handle refill submission
  const handleRefill = () => {
    onRefill(medication._id, refillQuantity);
    setShowRefillModal(false);
  };

  return (
    <>
      <div
        className={`card relative ${medication.needsRefill ? "border-2 border-red-300 bg-red-50" : ""}`}
      >
        {/* Refill Badge */}
        {medication.needsRefill && (
          <div className="absolute -top-2 -right-2">
            <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-red-500 text-white">
              Refill Needed
            </span>
          </div>
        )}

        {/* Medication Name */}
        <div className="flex items-start justify-between mb-4">
          <div>
            <h3 className="text-xl font-semibold text-gray-900">
              {medication.medicineName}
            </h3>
            <p className="text-sm text-gray-500">
              Started: {formatDate(medication.startDate)}
            </p>
          </div>
          {/* Delete Button */}
          <button
            onClick={() => onDelete(medication._id)}
            className="text-gray-400 hover:text-red-500 transition-colors"
            title="Delete medication"
          >
            <svg
              className="w-5 h-5"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"
              />
            </svg>
          </button>
        </div>

        {/* Pills Count Display */}
        <div className="flex items-baseline mb-2">
          <span
            className={`text-3xl font-bold ${medication.needsRefill ? "text-red-600" : "text-blue-600"}`}
          >
            {medication.remainingStock}
          </span>
          <span className="text-gray-500 ml-1">
            / {medication.totalQuantity} pills left
          </span>
        </div>

        {/* Progress Bar */}
        <div className="progress-bar mb-4">
          <div
            className={`progress-fill ${getProgressColor()}`}
            style={{ width: `${percentRemaining}%` }}
          ></div>
        </div>

        {/* Details Grid */}
        <div className="grid grid-cols-2 gap-3 text-sm mb-4">
          <div className="bg-gray-50 rounded-lg p-2">
            <span className="text-gray-500">Daily Dose</span>
            <p className="font-semibold text-gray-900">
              {medication.dailyDosage} pill
              {medication.dailyDosage > 1 ? "s" : ""}/day
            </p>
          </div>
          <div className="bg-gray-50 rounded-lg p-2">
            <span className="text-gray-500">Days Left</span>
            <p
              className={`font-semibold ${medication.daysRemaining <= 3 ? "text-red-600" : "text-gray-900"}`}
            >
              {medication.daysRemaining} days
            </p>
          </div>
          <div className="bg-gray-50 rounded-lg p-2">
            <span className="text-gray-500">Consumed</span>
            <p className="font-semibold text-gray-900">
              {medication.pillsConsumed} pills
            </p>
          </div>
          <div className="bg-gray-50 rounded-lg p-2">
            <span className="text-gray-500">Days Elapsed</span>
            <p className="font-semibold text-gray-900">
              {medication.daysElapsed} days
            </p>
          </div>
        </div>

        {/* Refill Button */}
        <button
          onClick={() => setShowRefillModal(true)}
          className={`w-full py-2 px-4 rounded-lg font-medium transition-colors ${
            medication.needsRefill
              ? "bg-red-600 hover:bg-red-700 text-white"
              : "bg-gray-100 hover:bg-gray-200 text-gray-700"
          }`}
        >
          {medication.needsRefill ? "🔔 Refill Now" : "Refill"}
        </button>
      </div>

      {/* Refill Modal */}
      {showRefillModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-xl shadow-xl max-w-md w-full p-6">
            <h3 className="text-xl font-bold text-gray-900 mb-4">
              Refill {medication.medicineName}
            </h3>
            <div className="mb-4">
              <label className="block text-sm font-medium text-gray-700 mb-2">
                New Quantity
              </label>
              <input
                type="number"
                value={refillQuantity}
                onChange={(e) => setRefillQuantity(Number(e.target.value))}
                className="input-field"
                min="1"
              />
              <p className="text-sm text-gray-500 mt-1">
                This will reset the start date to today.
              </p>
            </div>
            <div className="flex space-x-3">
              <button
                onClick={() => setShowRefillModal(false)}
                className="flex-1 btn-secondary"
              >
                Cancel
              </button>
              <button onClick={handleRefill} className="flex-1 btn-primary">
                Confirm Refill
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
}

export default MedicationCard;
